    {
        let n1 = s1.len() as int;
        let n2 = s2.len() as int;
        let n = n1 + n2;
        let p = Seq::new(n as nat, |i: int| if i < n2 { i + n1 } else { i - n2 });
        assert(is_valid_index_permutation(p, n)) by {
            assert(forall|i: int| 0 <= i < n ==> 0 <= #[trigger] p[i] < n);
